package com.aadil.jobtracker.security;import com.aadil.jobtracker.responses.AuthenticationResponse;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestBody;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;@RestController@RequestMapping("/api/auth")public class AuthenticationController {    private final AuthenticationService authenticationService;    public AuthenticationController(AuthenticationService authenticationService) {        this.authenticationService = authenticationService;    }    @PostMapping ("/register")    public ResponseEntity<AuthenticationResponse> register (@RequestBody RequestRegisterDTO register){       String token =  authenticationService.register(register);        return ResponseEntity.ok(new AuthenticationResponse(token,register.getEmail(),"User registered successfully"));    }    @PostMapping ("/login")    public ResponseEntity<AuthenticationResponse> login (LoginRequestDTO login){        String token  = authenticationService.login(login.getEmail(),login.getPassword());        return ResponseEntity.ok(new AuthenticationResponse(token,login.getEmail(),"User login Successfully"));    }}